/// Stop and remove the vLLM container.
pub async fn stop_vllm(&self) -> Result<()> {
    info!("Stopping vLLM container");
    self.docker.stop_container(VLLM_CONTAINER_NAME, None::<bollard::container::StopContainerOptions>).await
